			["sparkRotationMode"] = "AUTO",
			["automaticWidth"] = "Auto",
			["desaturateForeground"] = false,
			["triggers"] = {
				{
					["trigger"] = {
						["type"] = "custom",
						["custom_type"] = "stateupdate",
						["debuffType"] = "HELPFUL",
						["subeventSuffix"] = "_CAST_START",
						["event"] = "Health",
						["subeventPrefix"] = "SPELL",
						["names"] = {
						},
						["spellIds"] = {
						},
						["custom"] = "function(states, event, ...)\n  if event == \"GLOBAL_MOUSE_UP\" and ... then\n    local button = ...\n    if button == \"LeftButton\" then\n      if IsShiftKeyDown() then\n        for cloneID, region in pairs(aura_env.regions) do\n          local over = MouseIsOver(region)\n          if over and states[cloneID] then\n            local x, y = states[cloneID].X, states[cloneID].Y\n            if x ~= 0 and y ~=0 then\n              --local map = C_Map.GetBestMapForUnit(\"player\")\n              C_Map.SetUserWaypoint(UiMapPoint.CreateFromCoordinates(states[cloneID].zoneID, x/100, y/100, 0))\n              C_SuperTrack.SetSuperTrackedUserWaypoint(true)\n            end\n            break\n          end\n        end\n      elseif IsControlKeyDown() then\n        for cloneID, region in pairs(aura_env.regions) do\n          local over = MouseIsOver(region)\n          if over and states[cloneID] then\n            print(states[cloneID].disp)\n            for _, link in ipairs(states[cloneID].links) do\n              print(link)\n            end\n          end\n        end\n      end\n    elseif button == \"RightButton\" and IsShiftKeyDown() then\n      for cloneID, region in pairs(aura_env.regions) do\n        local over = MouseIsOver(region)\n        if over and states[cloneID] then\n          C_Map.ClearUserWaypoint()\n          break\n        end\n      end\n    end\n  else\n    local cfg = aura_env.config\n    local map = C_Map.GetBestMapForUnit(\"player\")\n    local class = select(3, UnitClass(\"player\"))\n    --print(\"------------------\")\n    local update\n    for _, rare in ipairs(cfg.rares) do\n      if rare.alwaysDisplay --or rare.classDisplay[class] --\n      then            \n        if type(rare.hiddenQuestId) == \"string\" then\n          local isCompleted = C_QuestLog.IsQuestFlaggedCompleted(rare.hiddenQuestId)\n          local skip = (cfg.hideCompleted and isCompleted) or (cfg.onlyElites and not rare.isElite)\n          \n          local inZone = true\n          local rareZone = aura_env.zones[rare.zone]\n          if rareZone.zoneId ~= map then\n            inZone = false\n          end\n          \n          if skip and states[rare.hiddenQuestId] then\n            states[rare.hiddenQuestId] = {\n              changed = true,\n              show = false,\n            }\n            update = true\n          elseif not skip and not states[rare.hiddenQuestId] then\n            local index = inZone and 0 or 10\n            index = index + rare.zone^2 + (rare.isElite and 0 or 1)\n            \n            local tooltip = format(\"%s|n|cFFFFFFFF/way %s %s|r\", rareZone.zone, rare.X, rare.Y)\n            \n            states[rare.hiddenQuestId] = {\n              icon = rare.isElite and 878214 or 4620677,\n              disp = rare.name,\n              zone = rareZone.zoneShort,\n              zoneID = rareZone.zoneId,\n              inZone = inZone,\n              isCompleted = isCompleted,\n              tooltip = tooltip,\n              tooltipWrap = true,\n              index = index,\n              links = {},\n              X = rare.X,\n              Y = rare.Y,\n              changed = true,\n              show = true,\n            }\n            for itemID in rare.drops:gmatch(\"%d+\") do\n              if itemID and itemID ~= \"\" then\n                itemID = tonumber(itemID)\n                local item = Item:CreateFromItemID(itemID)\n                local link\n                if item and not item:IsItemEmpty() then\n                  item:ContinueOnItemLoad(function()\n                      link = item:GetItemLink()\n                    end\n                  )\n                  table.insert(states[rare.hiddenQuestId].links, link)\n                end\n              end\n            end\n            update = true\n          elseif states[rare.hiddenQuestId]\n          and states[rare.hiddenQuestId].isCompleted ~= isCompleted\n          then\n            states[rare.hiddenQuestId].isCompleted = isCompleted\n            states[rare.hiddenQuestId].changed = true\n            update = true\n          elseif states[rare.hiddenQuestId]\n          and states[rare.hiddenQuestId].inZone ~= inZone\n          then\n            states[rare.hiddenQuestId].inZone = inZone\n            states[rare.hiddenQuestId].changed = true\n            update = true\n          end            \n        end\n      end\n    end\n    \n    return update\n  end\nend",
