			["displayText"] = "%c",
			["customText"] = "--Example code sent by m0nstah#9099 Thanks for the intial code as it got me started\n\nfunction()\n  -- Default Locale --\n  aura_env.defaultLocale = 'enUS'\n  -- User Locale Var--\n  aura_env.userLocale = GetLocale()\n  -- Get Text sinppet --\n  aura_env.get_text_snippet = function(name)\n    if aura_env.textSnippets[name] and aura_env.textSnippets[name][aura_env.userLocale] then\n      return aura_env.textSnippets[name][aura_env.userLocale]\n    end\n    if aura_env.textSnippets[name] and aura_env.textSnippets[name][aura_env.defaultLocale] then\n      return aura_env.textSnippets[name][aura_env.defaultLocale]\n    end\n    return name\n  end\n  -- World quest Availibility --\n  aura_env.is_world_quest_available = function(quest)\n    if not C_TaskQuest.GetQuestTimeLeftSeconds(quest) then\n      return true\n    end\n    return false\n  end\n  -- Quest Completion check --\n  aura_env.is_quest_completed = function(quest)\n    if C_QuestLog.IsQuestFlaggedCompleted(quest) then\n      return true\n    end\n    return false\n  end\n  local repPerHunt = 190\n  local huntSoundID = 7197\n  local trophysInBag = GetItemCount(200093)\n  local spoils = GetItemCount(200516)\n  local targetRenown = aura_env.config.mc.targetRenown\n  local repThreshold = aura_env.config.mc.repThreshold\n  local huntTime = aura_env.config.mc.timePerHunt\n  local renown10Buff = aura_env.config.mc.renown10Buff\n  local renown20Buff = aura_env.config.mc.renown20Buff\n  local playHuntSound = aura_env.config.mc.soundOnHuntFinish\n  local totalTrophys = trophysInBag + spoils * 4\n  local getAdjustedBuffMult = function(adjustedRep, renown10Buff, renown20Buff)\n    if adjustedRep < 25000 then\n      if renown20Buff then\n        return 3\n      else\n        if renown10Buff then\n          return 2\n        end\n        return 1\n      end\n    else\n      if adjustedRep < 50000 then\n        if renown20Buff then\n          return 2\n        end\n        return 1\n      else\n        return 1\n      end\n    end\n    return 1\n  end\n  \n  \n  if aura_env.lastTrophys == nil then\n    aura_env.lastTrophys = totalTrophys\n  end\n  if aura_env.lastTrophys > totalTrophys then\n    aura_env.lastTrophys = totalTrophys\n  end\n  if totalTrophys - aura_env.lastTrophys >= 4 and playHuntSound then\n    aura_env.lastTrophys = totalTrophys\n    PlaySound(huntSoundID, \"Master\", true)\n  end\n  \n  local trophyRepMult = 1\n  if aura_env.config.mc.darkMoonForTrophys then\n    trophyRepMult = trophyRepMult + 0.1\n    repPerHunt = repPerHunt + 10\n  end\n  \n  if aura_env.config.mc.useDarkmoonBuffForHunt then\n    repPerHunt = repPerHunt + 6\n  end\n  \n  \n  \n  local renownData = C_MajorFactions.GetMajorFactionData(2503)\n  local currentRep = renownData.renownReputationEarned\n  local renownLevel = renownData.renownLevel\n  local totalRenownNeeded = targetRenown * 2500 - repThreshold - renownLevel * 2500 - currentRep\n  \n  \n  local currentTrophyRep = totalTrophys * trophyRepMult * 25\n  if renown10Buff and renownLevel < 10 or renown20Buff and renownLevel < 20 then\n    local buffMult = 2\n    if renown10Buff and renownLevel < 10 and renown20Buff then\n      buffMult = 3\n    end\n    local trophys = totalTrophys\n    currentTrophyRep = 0\n    while trophys >= 20 do\n      currentTrophyRep = currentTrophyRep + 20 * 25 * trophyRepMult * buffMult\n      trophys = trophys - 20\n      local adjustedRep = renownLevel * 2500 + currentRep + currentTrophyRep\n      buffMult = getAdjustedBuffMult(adjustedRep, renown10Buff, renown20Buff)\n    end\n    while trophys >= 5 do\n      currentTrophyRep = currentTrophyRep + 5 * 25 * trophyRepMult * buffMult\n      trophys = trophys - 5\n      local adjustedRep = renownLevel * 2500 + currentRep + currentTrophyRep\n      buffMult = getAdjustedBuffMult(adjustedRep, renown10Buff, renown20Buff)\n    end\n    while trophys >= 1 do\n      currentTrophyRep = currentTrophyRep + 1 * 25 * trophyRepMult * buffMult\n      trophys = trophys - 1\n      local adjustedRep = renownLevel * 2500 + currentRep + currentTrophyRep\n      buffMult = getAdjustedBuffMult(adjustedRep, renown10Buff, renown20Buff)\n    end\n  end\n  local renownNeededAfterTrophys = totalRenownNeeded - currentTrophyRep\n  local huntsNeeded = 0\n  local repSimLevel = currentRep + renownLevel * 2500 + currentTrophyRep + repThreshold\n  while repSimLevel < targetRenown * 2500 do\n    huntsNeeded = huntsNeeded + 1\n    local currentRepHuntMult = 1\n    if repSimLevel < 25000 and renown10Buff or repSimLevel < 50000 and renown20Buff then\n      currentRepHuntMult = 2\n    end\n    if repSimLevel < 25000 and renown10Buff and renown20Buff then\n      currentRepHuntMult = 3\n    end\n    repSimLevel = repSimLevel + repPerHunt * currentRepHuntMult\n  end\n  local timeNeeded = huntsNeeded * huntTime\n  local hours = math.floor(timeNeeded/60)\n  local minutes = timeNeeded - hours*60\n  local text = \"\"\n  if aura_env.config.mc.Show then\n    text = text..\"|cffff4400Maruuk|r \\n|cff00ffaaCurrently Renown|r = |cffff4400\"..renownLevel..\"|r|cff00ffaa | |r|cffff4400\"..currentRep..\"|r|cff00ffaa Rep.\\nCurrent Target is|r =|cffff4400 \"..targetRenown..\"|r\"\n    if renownNeededAfterTrophys > 0 then\n      text = text..\"\\n|cff00ffaaRep Required|r =|cffff4400 \"..renownNeededAfterTrophys..\"|r\"\n    end\n    if totalTrophys > 0 then\n      text = text..\"\\n|cff00ffaaTrophys in Bag|r = |cff00aaff\"..totalTrophys..\"|r\"\n    end\n    text = text..\"\\n|cff00ffaaApprox Hunts Left|r = |cff00aaff\"..huntsNeeded..\"|r\"\n    text = text..\"\\n|cff00ffaaTime to target|r =  |cff00aaff\"..hours..\"H:\"..minutes..\"M.|\\n\"\n  end\n  return text\n  \nend\n\n\n",
