			["wagoID"] = "9MpDLGWp3",
			["xOffset"] = 0,
			["displayText"] = "%c",
			["customText"] = "function()\n  local text =\"|cff00ffaaUser Guide/set up|r. \\n\\n|cffff0000Please note this is note displayed when you close the main weak auras window config window|r\\n\\n\"\n  text = text..\"|cffffaa00Groups list as \\\"<name> Module\\\" can be moved independantly of each other. the items within the Modules are linked and should not be moved/changed.\\n\\n\"\n  text = text..\"if you wish to edit or modify the code you are free todo so however im unable to support these modifications\\n\\n\"\n  text = text..\"please do not delete elements if you dont wish to use a module click on it then go to custom options and set to off (you can also use the never load condiationshould you to too)|r\\n\\n\"\n  ---- Weekly/Daily Module info----\n  text = text..\"|cff0055FF Weekly/Daily Module|r|cff00ff55 (On by default)|r\\nBase module that started it all tracks renown/rares and general weekly todo items\\n\\n\"\n  ---- Primals Module info----\n  text = text..\"|cff0055F Primals Module|r |cffff0066(Off by default)|r\\nThis module will only load at level 70 when you can do the primal storms post item level 385 this will most like stay turned off \\n\\n\"\n  ---- Rep calc Module info----\n  text = text..\"|cff0055FFRep calc Module|r |cffff0066(Off by default)|r\\nThis module allows you to work out the time needed to get to a rep with passive rep options\\n\\n\"\n  ----profssion module info----\n  text = text..\"|cff0055FFProfession Module|r|cff00ff55 (On by default)|r\\nThis module includes all your crafting one time the weekly collectables (in a future update weekly profession quest will be added)\\n|cffaa22FFTreatise of <profession name>|r are crafted by inscriptionist and can be purchsed via the work order system for 1 rep per week)\\n\\n\"\n  \n  text = text..\"|cffff0000work in progress more will be added here!|r\"\n  return text\nend",
