			["customText"] = "--rep sources\n--1. Sacred Totems: the route I posted earlier - 15 rep for each\n--2. Community Feast, 3-4-5 per day: 650-750 reputation for each event (for that you need to be on a free layer, where there are few players near the event - no more than 15-20)\n--3. Daily: fishing quests, x2 - 150 rep each\n--4. Daily: Super rares in the Azure x4 - 50 for each. (Spawn every 10 minutes 1 out of 4)\n--5. Daily: Normal rares in the Azure - 50 each. (I found no more than 2-3)\n--6. Daily: Rares for Ominous Conch x3 - 50 rep for each (LFG-Other: \"fishing\")\n--7. Weekly: World Quests (2 times a week) - 200-400 rep per update\n--8. Weekly: Faction Reputation Quests - 500 rep\n--9. Weekly: quests for dungeons x2 - 500 rep for each\n\nfunction()\n  local targetRenown = aura_env.config.it.targetRenown\n  local repPerFeast = 325 -- can be as mich as 675 if your on a quite shard but its more common to be 300 to 350\n  local renown10Buff = aura_env.config.it.renown10Buff\n  local renown20Buff = aura_env.config.it.renown20Buff\n  local TotemsInBag = GetItemCount(200071) -- 15 rep \n  local FishingQs = 300 --Daily:  x2 - 150 rep each\n  local BrakRares = 200  --Daily:  x4 - 50 daily per rare\n  local worldquest = 600 -- Weekly: 200-400 rep per update\n  local Dungeon = 1000 -- Weekly: quests for dungeons x2 - 500 rep for each\n  local renownData = C_MajorFactions.GetMajorFactionData(2511)\n  local currentRep = renownData.renownReputationEarned\n  local renownLevel = renownData.renownLevel\n  local WeeklyTotal = (FishingQs*7)+(BrakRares*7)+worldquest+Dungeon--+(*7)\n  local reptotal = targetRenown*2500\n  local repneeded = reptotal -(currentRep + 2500 * renownLevel)\n  \n  local feastsNeeded = 0\n  local repSimLevel = currentRep + 2500 * renownLevel\n  while repSimLevel < targetRenown * 2500 do\n    feastsNeeded = feastsNeeded + 1\n    local currentRepFeastMult = 1\n    if repSimLevel < 25000 and renown10Buff or repSimLevel < 50000 and renown20Buff then\n      currentRepFeastMult = 2\n    end\n    if repSimLevel < 25000 and renown10Buff and renown20Buff then\n      currentRepFeastMult = 3\n    end\n    repSimLevel = repSimLevel + repPerFeast * currentRepFeastMult\n  end\n  local feastTime = 210\n  local timeNeeded = feastsNeeded * feastTime\n  local days = math.floor(timeNeeded/60/24)\n  local timelessdays = timeNeeded - days*60*24\n  local hours = math.floor(timelessdays/60)\n  local minutes = timelessdays - (hours*60)\n  \n  local text = \"\"\n  if aura_env.config.it.show then\n    text = text..\"|cff0055ffIskaara Tuskar|r\\n|cff00ffaaCurrently Renown|r = |cff0055ff\"..renownLevel..\"|r|cff00ffaa | |r|cff0055ff\"..currentRep..\"|r|cff00ffaa Rep|r.\\n|cff00ffaaCurrent Target is|r =|cff0055ff \"..targetRenown..\"|r.\"\n    text = text..\"\\n|cff00ffaaRep required|r =|cff0055ff \"..repneeded..\"|r.\"\n    if TotemsInBag >0 then\n      text = text..\"\\n|cff00ffaaSacred Totems in bag|r = |cff00aaff\"..TotemsInBag..\"|r.\"\n    end\n    \n    text = text..\"\\n|cff00ffaaApprox Feast left|r = |cff00aaff\"..feastsNeeded..\"|r.\"\n    text = text..\"\\n|cff00ffaaTime to target|r =  |cff00aaff\"..days..\"D: \"..hours..\"H:\"..minutes..\"M|r.\"\n  end\n  -- text = text..\"\\n|cff00ffaaWeekly Rep|r = \"..WeeklyTotal\n  return text\nend\n-- icon 4638464\n\n\n",
