						["spellIds"] = {
						},
						["custom"] = "function(states, event, ...)\n  local cfg = aura_env.config\n  local update\n  for _, rare in ipairs(cfg.prares) do\n    \n    -- check storm\n    local storm = aura_env.storms[rare.storm]\n    local isActive = aura_env.isActive(storm)\n    \n    -- check completion\n    local isCompleted = C_QuestLog.IsQuestFlaggedCompleted(rare.questID)\n    local skip = (cfg.rareSettings.hideComplete and isCompleted) or (not cfg.rareSettings.primalEnable) or (cfg.rareSettings.primalActive and not isActive)\n    \n    \n    if skip and states[rare.questID] then\n      states[rare.questID] = { changed = true, show = false }\n      update = true\n      \n    elseif not skip and not states[rare.questID] then\n      \n      local index = rare.name\n      \n      \n      states[rare.questID] = {\n        disp = rare.name,\n        storm = storm,\n        isCompleted = isCompleted,\n        index = index,\n        links = {},\n        X = rare.X,\n        Y = rare.Y,\n        changed = true,\n        show = true\n      }            \n      \n      update = true\n    elseif states[rare.questID] and states[rare.questID].isCompleted ~= isCompleted then\n      states[rare.questID].isCompleted = isCompleted\n      states[rare.questID].changed = true\n      update = true\n    end            \n  end\n  \n  return update\nend\n\n\n\n\n\n\n\n",
