			["actions"] = {
				["start"] = {
					["custom"] = "local region = WeakAuras.GetRegion(aura_env.id, aura_env.cloneId)\nif region and region.state and region.state.show then\n  aura_env.regions[aura_env.cloneId] = region\nend",
					["do_custom"] = true,
