						["custom_type"] = "status",
						["check"] = "event",
						["custom"] = "function()\n    if not aura_env.config[\"timers\"].primalStorm then return false end\n    \n    -- iterate zones\n    for zoneID in pairs(aura_env.zoneID) do\n        \n        --iterate POI elements\n        for _, poi in ipairs(C_AreaPoiInfo.GetAreaPOIForMap(zoneID)) do\n            \n            -- is elemental storm up AND is this the zone\n            if C_AreaPoiInfo.GetAreaPOIInfo(zoneID,poi).name == \"Elemental Storm\" and C_AreaPoiInfo.GetAreaPOIInfo(zoneID,poi).isPrimaryMapForPOI then\n                local n = C_AreaPoiInfo.GetAreaPOIInfo(zoneID,poi).atlasName\n                local f = select(1,strsplit(\"-\",n))\n                \n                -- check for the storm we care about\n                if f == \"ElementalStorm\" then\n                    if select(3,strsplit(\"-\",n)) == \"Air\" then\n                        aura_env.zone = aura_env.zoneID[zoneID]\n                        return true\n                    end\n                end\n            end\n        end\n    end\nend\n\n\n\n",
