		["Weekly core hand-ins"] = {
			["outline"] = "OUTLINE",
			["displayText_format_text_format"] = "none",
			["wagoID"] = "9MpDLGWp3",
			["parent"] = "Primals Module (off by default turn on in Custom options)",
			["displayText"] = "%c",
			["customText"] = "function()\n    \n    aura_env.text = aura_env.update_display()\n    \n    return aura_env.text \nend",
			["shadowYOffset"] = -1,
			["anchorPoint"] = "TOPLEFT",
			["displayText_format_p_time_format"] = 0,
			["customTextUpdate"] = "event",
			["url"] = "https://wago.io/TamasDragonflightHelper/74",
			["actions"] = {
				["start"] = {
				},
				["finish"] = {
				},
				["init"] = {
					["custom"] = "--code is a modified version of Korthia Checklist https://wago.io/cyRj6ikQz by Dorovon#1260 for the original todo lists in korthia\n-- Default Locale --\naura_env.defaultLocale = 'enUS'\n-- User Locale Var--\naura_env.userLocale = GetLocale()\n-- Get Text sinppet --\naura_env.get_text_snippet = function(name)\n  if aura_env.textSnippets[name] and aura_env.textSnippets[name][aura_env.userLocale] then\n    return aura_env.textSnippets[name][aura_env.userLocale]\n  end\n  if aura_env.textSnippets[name] and aura_env.textSnippets[name][aura_env.defaultLocale] then\n    return aura_env.textSnippets[name][aura_env.defaultLocale]\n  end\n  return name\nend\n-- World quest Availibility --\naura_env.is_world_quest_available = function(quest)\n  if not C_TaskQuest.GetQuestTimeLeftSeconds(quest) then\n    return true\n  end\n  return false\nend\n-- Quest Completion check --\naura_env.is_quest_completed = function(quest)\n  if C_QuestLog.IsQuestFlaggedCompleted(quest) then\n    return true\n  end\n  return false\nend\n\n-- Title items --\n\naura_env.textSnippets = {\n  overviewHeadline = { enUS = ' Primal Core handin:',\n    deDE = 'Elementarstürme:',\n    zhTW = 'storms:',\n    zhCN = 'storms:',\n    ruRU = 'storms:',\n    frFR = 'storms:',\n    jaJP = 'storms:',\n    koKR = 'storms:',\n  },\n  \n  fire= {\n    enUS = 'Extinguishing the Fire Primalists',\n    deDE = 'Die Feuerprimalisten löschen:',\n    zhTW = 'Fire:',\n    zhCN = 'Fire:',\n    ruRU = 'Fire:',\n    frFR = 'Fire:',\n    nlNL = 'Fire:',\n    jaJP = 'Fire:',\n    koKR = 'Fire:',\n  },\n  \n  water = {\n    enUS = 'Vaporizing the Water Primalists:',\n    deDE = 'Die Wasserprimalisten verdampfen:',\n    zhTW = 'Water:',\n    zhCN = 'Water:',\n    ruRU = 'Water:', \n    frFR = 'Water:',\n    nlNL = 'Water:',\n    jaJP = 'Water:',\n    koKR = 'Water:',\n  },\n  \n  earth = {\n    enUS = 'Shattering the Earth Primalists: ',\n    deDE = 'Die Erdprimalisten zerschmettern:',\n    zhTW = 'Earth:', \n    zhCN = 'Earth:',\n    ruRU = 'Earth:',\n    frFR = 'Earth:',\n    nlNL = 'Earth:',\n    jaJP = 'Earth:',\n    koKR = 'Earth:',\n  },\n  \n  air = {\n    enUS = 'Dissipating the Air Primalists: ',\n    deDE = 'Die Luftprimalisten verwehen: ',\n    zhTW = 'Air: ', \n    zhCN = 'Air: ',\n    ruRU = 'Air: ',\n    frFR = 'Air: ',\n    nlNL = 'Air',\n    jaJP = 'Air',\n    koKR = 'Air',\n  },\n}\n-- TODO - Items --\naura_env.todoList = {\n  --  {name = \"overviewHeadline\" },\n  {name = \"fire\",maximum = 1,\n    quests = {\n      {questId = 70754,},--Extinguishing the Fire Primalists--70754--\n    },\n  },\n  {name = \"water\",maximum = 1,\n    quests = {\n      {questId = 70752,}, --Vaporizing the Water Primalists--70752--\n    },\n  },\n  {name = \"earth\",maximum = 1,\n    quests = {\n      {questId = 70723,}, --Shattering the Earth Primalists -- 70723???--\n    },\n  },\n  \n  { name = \"air\",  maximum = 1,\n    quests = {\n      {questId = 70753,},-- Dissipating the Air Primalists--70753--\n      \n    },\n  },\n  \n}\n\n--Output Varible--\naura_env.text = '';\n--Output Main function--\naura_env.update_overview_display = function()\n  local text = ''\n  local hide = aura_env.config.PS.hidefireIfCompleted\n  -----------------------------------------------------Todo list Prep--------------------------------------------------------------------------- \n  for _, todoEntry in ipairs(aura_env.todoList) do\n    -- PINK --\n    local entry, color, completed, maximum = '', 'ffff00ff', 0, #todoEntry.quests\n    if \n    \n    --set up the items to display\n    todoEntry.name == 'fire' or\n    todoEntry.name == 'water'or\n    todoEntry.name == 'earth'or\n    todoEntry.name == 'air' then\n      if todoEntry.maximum then\n        maximum = todoEntry.maximum\n      end\n      for _, todoQuest in ipairs(todoEntry.quests) do\n        if todoEntry.name == 'worldBoss' then\n          if aura_env.is_quest_completed(todoQuest.questId) then\n            completed = completed + 1\n          end\n        else\n          if aura_env.is_quest_completed(todoQuest.questId) then\n            completed = completed + 1\n          end\n        end\n      end\n      if (maximum > 1) and (completed >= (maximum / 2)) then\n        -- Burnt Orange --\n        color = 'ffff7801'\n      end \n      if completed >= maximum then\n        -- JADE--\n        color = 'FF00ff96'\n      end\n      \n      if completed >= maximum then\n        if\n        todoEntry.name == 'water' and not hide or \n        todoEntry.name == 'fire' and not hide or\n        todoEntry.name == 'earth' and not hide or \n        todoEntry.name == 'air' and not hide then\n          entry ='    ' ..  aura_env.get_text_snippet(todoEntry.name) .. ' ' .. WrapTextInColorCode(completed .. ' / ' .. maximum, color) .. '\\r\\n'\n        end\n      else\n        entry ='    ' .. aura_env.get_text_snippet(todoEntry.name) .. ' ' .. WrapTextInColorCode(completed .. ' / ' .. maximum, color) .. '\\r\\n'\n      end\n      \n      text = text .. entry\n    end\n  end\n  \n  return text\nend\n\n--Update output varible--\naura_env.update_display = function()\n  local text = ''\n  ---todo list items update---\n  if aura_env.config.PS.showOverviewps then -- cheack if use want to show\n    \n    text = text..aura_env.update_overview_display()..'\\n' --append todo list items\n  end \n  return text\nend\naura_env.text = aura_env.update_display()\n\n\n\n",
					["do_custom"] = true,
				},
			},
